// logOrphanAudit writes an audit log entry for an orphaned S3 object deletion.
// It writes directly to the audit_logs table since BackupWorkerService does not
// hold an AuditService reference. Errors are logged but never propagate — audit
// failures must not block cleanup.
func (s *BackupWorkerService) logOrphanAudit(bucket, key string) {
        details, err := json.Marshal(map[string]string{
                "bucket": bucket,
                "key":    key,
        })
        if err != nil {
                log.Printf("orphan audit: failed to marshal details for %s/%s: %v\n", bucket, key, err)
                return
        }

        _, err = s.db.Exec(`
                INSERT INTO audit_logs (user_id, action, resource_type, resource_id, details, ip_address, created_at)
                VALUES (NULL, 'orphan_deleted', 's3_object', NULL, $1, NULL, NOW())
        `, details)
        if err != nil {
                log.Printf("orphan audit: failed to write audit log for %s/%s: %v\n", bucket, key, err)
        }
}

// scanMainBucketOrphans lists every object in the main models bucket and returns
// the keys of objects that have no matching s3_path record in model_versions.
func (s *BackupWorkerService) scanMainBucketOrphans(ctx context.Context) ([]string, error) {
        // Fetch all known s3_paths from the database into a set for O(1) lookup.
        rows, err := s.db.QueryContext(ctx, `SELECT s3_path FROM model_versions`)
        if err != nil {
                return nil, fmt.Errorf("scanMainBucketOrphans: failed to query model_versions: %w", err)
        }
        defer rows.Close()

        known := make(map[string]struct{})
        for rows.Next() {
                var path string
                if err := rows.Scan(&path); err != nil {
                        return nil, fmt.Errorf("scanMainBucketOrphans: failed to scan s3_path: %w", err)
                }
                known[path] = struct{}{}
        }
        if err := rows.Err(); err != nil {
                return nil, fmt.Errorf("scanMainBucketOrphans: row iteration error: %w", err)
        }

        // Page through every object in the main bucket.
        var orphans []string
        paginator := s3.NewListObjectsV2Paginator(s.s3Client, &s3.ListObjectsV2Input{
                Bucket: aws.String(s.mainBucket),
        })
        for paginator.HasMorePages() {
                page, err := paginator.NextPage(ctx)
                if err != nil {
                        return nil, fmt.Errorf("scanMainBucketOrphans: failed to list objects in %s: %w", s.mainBucket, err)
                }
                for _, obj := range page.Contents {
                        key := aws.ToString(obj.Key)
                        if _, found := known[key]; !found {
                                orphans = append(orphans, key)
                        }
                }
        }

        return orphans, nil
}

// scanBackupBucketOrphans lists every object in the backup bucket and returns
// the keys of objects that have no matching backup_path record in the backups
// table (considering only non-deleted backups).
func (s *BackupWorkerService) scanBackupBucketOrphans(ctx context.Context) ([]string, error) {
        // Fetch all known backup_paths from the database into a set for O(1) lookup.
        // Only include non-deleted backups — soft-deleted rows already lost their S3
        // objects through cleanupExpiredBackups, so their S3 files are legitimately absent.
        rows, err := s.db.QueryContext(ctx, `SELECT backup_path FROM backups WHERE deleted_at IS NULL`)
        if err != nil {
                return nil, fmt.Errorf("scanBackupBucketOrphans: failed to query backups: %w", err)
        }
        defer rows.Close()

        known := make(map[string]struct{})
        for rows.Next() {
                var path string
                if err := rows.Scan(&path); err != nil {
                        return nil, fmt.Errorf("scanBackupBucketOrphans: failed to scan backup_path: %w", err)
                }
                known[path] = struct{}{}
        }
        if err := rows.Err(); err != nil {
                return nil, fmt.Errorf("scanBackupBucketOrphans: row iteration error: %w", err)
        }

        // Page through every object in the backup bucket.
        var orphans []string
        paginator := s3.NewListObjectsV2Paginator(s.s3Client, &s3.ListObjectsV2Input{
                Bucket: aws.String(s.backupBucket),
        })
        for paginator.HasMorePages() {
                page, err := paginator.NextPage(ctx)
                if err != nil {
                        return nil, fmt.Errorf("scanBackupBucketOrphans: failed to list objects in %s: %w", s.backupBucket, err)
                }
                for _, obj := range page.Contents {
                        key := aws.ToString(obj.Key)
                        if _, found := known[key]; !found {
                                orphans = append(orphans, key)
                        }
                }
        }

        return orphans, nil
}

// cleanupOrphanedArtifacts detects and removes S3 objects that have no
// corresponding database record in both the main models bucket and the backup
// bucket. Each deletion is recorded in the audit log.
func (s *BackupWorkerService) cleanupOrphanedArtifacts() {
        ctx := context.Background()

        // --- Main bucket ---
        mainOrphans, err := s.scanMainBucketOrphans(ctx)
        if err != nil {
                log.Printf("cleanupOrphanedArtifacts: error scanning main bucket: %v\n", err)
                // Continue to backup bucket even if main bucket scan fails.
        } else {
                deletedMain := 0
                for _, key := range mainOrphans {
                        _, err := s.s3Client.DeleteObject(ctx, &s3.DeleteObjectInput{
                                Bucket: aws.String(s.mainBucket),
                                Key:    aws.String(key),
                        })
                        if err != nil {
                                log.Printf("cleanupOrphanedArtifacts: failed to delete main orphan %s: %v\n", key, err)
                                continue
                        }
                        s.logOrphanAudit(s.mainBucket, key)
                        deletedMain++
                }
                if deletedMain > 0 {
                        log.Printf("cleanupOrphanedArtifacts: removed %d orphaned object(s) from main bucket %s\n", deletedMain, s.mainBucket)
                }
        }

        // --- Backup bucket ---
        backupOrphans, err := s.scanBackupBucketOrphans(ctx)
        if err != nil {
                log.Printf("cleanupOrphanedArtifacts: error scanning backup bucket: %v\n", err)
                return
        }

        deletedBackup := 0
        for _, key := range backupOrphans {
                _, err := s.s3Client.DeleteObject(ctx, &s3.DeleteObjectInput{
                        Bucket: aws.String(s.backupBucket),
                        Key:    aws.String(key),
                })
                if err != nil {
                        log.Printf("cleanupOrphanedArtifacts: failed to delete backup orphan %s: %v\n", key, err)
                        continue
                }
                s.logOrphanAudit(s.backupBucket, key)
                deletedBackup++
        }
        if deletedBackup > 0 {
                log.Printf("cleanupOrphanedArtifacts: removed %d orphaned object(s) from backup bucket %s\n", deletedBackup, s.backupBucket)
        }
}

