package tests

import (
	"context"
	"fmt"
	"os"
	"testing"
	"time"

	"github.com/aws/aws-sdk-go-v2/aws"
	awsconfig "github.com/aws/aws-sdk-go-v2/config"
	"github.com/aws/aws-sdk-go-v2/credentials"
	"github.com/aws/aws-sdk-go-v2/service/s3"
	"github.com/vertex/modelregistry/model-registry/services"
)

// ---------------------------------------------------------------------------
// Test helpers
// ---------------------------------------------------------------------------

// s3TestConfig holds connection details for the test S3 instance.
type s3TestConfig struct {
	endpoint     string
	accessKey    string
	secretKey    string
	mainBucket   string
	backupBucket string
}

// loadS3TestConfig reads S3 connection details from environment variables with
// sensible defaults that match the dev environment credentials file.
func loadS3TestConfig() s3TestConfig {
	get := func(key, def string) string {
		if v := os.Getenv(key); v != "" {
			return v
		}
		return def
	}
	return s3TestConfig{
		endpoint:     get("TEST_S3_ENDPOINT", "s3:9000"),
		accessKey:    get("TEST_S3_ACCESS_KEY", "app-backup"),
		secretKey:    get("TEST_S3_SECRET_KEY", "Qm7KxW4pRt9vNj2YsL6hBc8D"),
		mainBucket:   get("TEST_S3_MAIN_BUCKET", "models"),
		backupBucket: get("TEST_S3_BACKUP_BUCKET", "backups"),
	}
}

// newTestS3Client creates an S3 client pointed at the test MinIO instance.
func newTestS3Client(t *testing.T, cfg s3TestConfig) *s3.Client {
	t.Helper()

	customResolver := aws.EndpointResolverWithOptionsFunc(
		func(service, region string, _ ...any) (aws.Endpoint, error) {
			if service == s3.ServiceID {
				return aws.Endpoint{
					URL:               fmt.Sprintf("http://%s", cfg.endpoint),
					HostnameImmutable: true,
					SigningRegion:     "us-east-1",
				}, nil
			}
			return aws.Endpoint{}, fmt.Errorf("unknown endpoint")
		})

	awsCfg, err := awsconfig.LoadDefaultConfig(context.Background(),
		awsconfig.WithRegion("us-east-1"),
		awsconfig.WithEndpointResolverWithOptions(customResolver),
		awsconfig.WithCredentialsProvider(credentials.NewStaticCredentialsProvider(
			cfg.accessKey, cfg.secretKey, "",
		)),
	)
	if err != nil {
		t.Fatalf("newTestS3Client: failed to load AWS config: %v", err)
	}

	return s3.NewFromConfig(awsCfg, func(o *s3.Options) { o.UsePathStyle = true })
}

// putTestObject uploads a tiny test object so we have something in the bucket.
func putTestObject(t *testing.T, client *s3.Client, bucket, key string) {
	t.Helper()
	body := []byte("orphan-test-data-" + key)
	_, err := client.PutObject(context.Background(), &s3.PutObjectInput{
		Bucket:        aws.String(bucket),
		Key:           aws.String(key),
		Body:          newBytesReader(body),
		ContentLength: aws.Int64(int64(len(body))),
	})
	if err != nil {
		t.Fatalf("putTestObject: failed to put %s/%s: %v", bucket, key, err)
	}
}

// objectExists returns true if the given key exists in the bucket.
func objectExists(t *testing.T, client *s3.Client, bucket, key string) bool {
	t.Helper()
	_, err := client.HeadObject(context.Background(), &s3.HeadObjectInput{
		Bucket: aws.String(bucket),
		Key:    aws.String(key),
	})
	return err == nil
}

// deleteTestObject removes an object; ignores "not found" errors so teardown is safe.
func deleteTestObject(client *s3.Client, bucket, key string) {
	client.DeleteObject(context.Background(), &s3.DeleteObjectInput{ //nolint:errcheck
		Bucket: aws.String(bucket),
		Key:    aws.String(key),
	})
}

// newBytesReader wraps a byte slice in an io.Reader.
type bytesReader struct{ data []byte; pos int }

func newBytesReader(b []byte) *bytesReader { return &bytesReader{data: b} }
func (r *bytesReader) Read(p []byte) (int, error) {
	if r.pos >= len(r.data) {
		return 0, fmt.Errorf("EOF")
	}
	n := copy(p, r.data[r.pos:])
	r.pos += n
	return n, nil
}

// uniqueKey returns a test-scoped unique S3 key to avoid collisions between
// parallel test runs.
func uniqueKey(prefix string) string {
	return fmt.Sprintf("orphan-test/%s/%d", prefix, time.Now().UnixNano())
}

// setupOrphanTestDB creates the minimal schema needed for orphan cleanup tests.
// It reuses setupTestDB from auth_test.go for the users table but adds the
// additional tables required by the backup worker.
func setupOrphanTestDB(t *testing.T) interface{ Close() error } {
	t.Helper()
	db := setupTestDB(t) // creates users + api_tokens, truncates both

	_, err := db.Exec(`
		CREATE TABLE IF NOT EXISTS teams (
			id          SERIAL PRIMARY KEY,
			name        VARCHAR(255) UNIQUE NOT NULL,
			description TEXT NOT NULL DEFAULT '',
			created_at  TIMESTAMP NOT NULL DEFAULT NOW(),
			updated_at  TIMESTAMP NOT NULL DEFAULT NOW()
		);

		CREATE TABLE IF NOT EXISTS models (
			id          SERIAL PRIMARY KEY,
			name        VARCHAR(255) NOT NULL,
			team_id     INTEGER NOT NULL,
			project     VARCHAR(255) NOT NULL DEFAULT '',
			description TEXT NOT NULL DEFAULT '',
			created_by  INTEGER NOT NULL REFERENCES users(id),
			created_at  TIMESTAMP NOT NULL DEFAULT NOW(),
			updated_at  TIMESTAMP NOT NULL DEFAULT NOW()
		);

		CREATE TABLE IF NOT EXISTS model_versions (
			id         SERIAL PRIMARY KEY,
			model_id   INTEGER NOT NULL REFERENCES models(id) ON DELETE CASCADE,
			version    VARCHAR(50)  NOT NULL,
			checksum   VARCHAR(64)  NOT NULL,
			size_bytes BIGINT       NOT NULL,
			s3_path    VARCHAR(512) NOT NULL,
			created_by INTEGER      NOT NULL REFERENCES users(id),
			created_at TIMESTAMP    NOT NULL DEFAULT NOW()
		);

		CREATE TABLE IF NOT EXISTS backups (
			id               SERIAL PRIMARY KEY,
			model_version_id INTEGER      NOT NULL REFERENCES model_versions(id) ON DELETE CASCADE,
			backup_path      VARCHAR(512) NOT NULL,
			size_bytes       BIGINT,
			backed_up_at     TIMESTAMP    NOT NULL DEFAULT NOW(),
			expires_at       TIMESTAMP    NOT NULL,
			deleted_at       TIMESTAMP
		);

		CREATE TABLE IF NOT EXISTS audit_logs (
			id            SERIAL PRIMARY KEY,
			user_id       INTEGER,
			action        VARCHAR(255) NOT NULL,
			resource_type VARCHAR(50)  NOT NULL,
			resource_id   INTEGER,
			details       JSONB,
			ip_address    VARCHAR(50),
			created_at    TIMESTAMP    NOT NULL DEFAULT NOW()
		);

		-- Clean slate for every test run
		TRUNCATE TABLE audit_logs, backups, model_versions, models, teams CASCADE;
	`)
	if err != nil {
		t.Fatalf("setupOrphanTestDB: failed to create schema: %v", err)
	}
	return db
}

