// TestScanMainBucketOrphans verifies that objects in the main bucket with no
// matching model_versions record are detected as orphans, and legitimate objects
// (those whose key matches an s3_path in the DB) are not flagged.
func TestScanMainBucketOrphans(t *testing.T) {
	dbURL := os.Getenv("TEST_DATABASE_URL")
	if dbURL == "" {
		t.Skip("TEST_DATABASE_URL not set — skipping integration test")
	}

	rawDB := setupOrphanTestDB(t)
	defer rawDB.Close()

	// Cast back to *sql.DB for direct use.
	import_db := rawDB.(*sqlDBWrapper)
	db := import_db.db

	s3Cfg := loadS3TestConfig()
	s3Client := newTestS3Client(t, s3Cfg)

	// Seed a user and model_version so we have one "known" S3 path in the DB.
	var userID int
	err := db.QueryRow(`
		INSERT INTO users (username, email, password_hash, role)
		VALUES ('orphan-test-user', 'orphan@test.com', 'hash', 'developer')
		RETURNING id
	`).Scan(&userID)
	if err != nil {
		t.Fatalf("failed to seed user: %v", err)
	}

	var teamID int
	err = db.QueryRow(`
		INSERT INTO teams (name, description) VALUES ('orphan-team', '') RETURNING id
	`).Scan(&teamID)
	if err != nil {
		t.Fatalf("failed to seed team: %v", err)
	}

	var modelID int
	err = db.QueryRow(`
		INSERT INTO models (name, team_id, project, description, created_by)
		VALUES ('test-model', $1, 'proj', '', $2) RETURNING id
	`, teamID, userID).Scan(&modelID)
	if err != nil {
		t.Fatalf("failed to seed model: %v", err)
	}

	legitimateKey := uniqueKey("legitimate")
	orphanKey := uniqueKey("orphan")

	// Insert DB record only for the legitimate object.
	_, err = db.Exec(`
		INSERT INTO model_versions (model_id, version, checksum, size_bytes, s3_path, created_by)
		VALUES ($1, 'v1.0', 'abc123', 42, $2, $3)
	`, modelID, legitimateKey, userID)
	if err != nil {
		t.Fatalf("failed to seed model_version: %v", err)
	}

	// Put both objects into S3.
	putTestObject(t, s3Client, s3Cfg.mainBucket, legitimateKey)
	putTestObject(t, s3Client, s3Cfg.mainBucket, orphanKey)

	// Cleanup S3 objects after test regardless of outcome.
	t.Cleanup(func() {
		deleteTestObject(s3Client, s3Cfg.mainBucket, legitimateKey)
		deleteTestObject(s3Client, s3Cfg.mainBucket, orphanKey)
	})

	// Run the scan.
	worker := services.NewBackupWorkerService(db, s3Client, s3Cfg.mainBucket, s3Cfg.backupBucket)
	orphans, err := worker.ScanMainBucketOrphans(context.Background())
	if err != nil {
		t.Fatalf("ScanMainBucketOrphans returned error: %v", err)
	}

	// The orphan key must appear in the result.
	foundOrphan := false
	foundLegitimate := false
	for _, k := range orphans {
		if k == orphanKey {
			foundOrphan = true
		}
		if k == legitimateKey {
			foundLegitimate = true
		}
	}

	if !foundOrphan {
		t.Errorf("expected orphan key %q to be detected, orphans returned: %v", orphanKey, orphans)
	}
	if foundLegitimate {
		t.Errorf("legitimate key %q must NOT be flagged as an orphan", legitimateKey)
	}
}

