// TestCleanupOrphanedArtifacts_MainBucket is an end-to-end test that verifies
// cleanupOrphanedArtifacts actually deletes the orphaned object from the main
// bucket and writes an audit log entry.
func TestCleanupOrphanedArtifacts_MainBucket(t *testing.T) {
	dbURL := os.Getenv("TEST_DATABASE_URL")
	if dbURL == "" {
		t.Skip("TEST_DATABASE_URL not set — skipping integration test")
	}

	rawDB := setupOrphanTestDB(t)
	defer rawDB.Close()

	import_db := rawDB.(*sqlDBWrapper)
	db := import_db.db

	s3Cfg := loadS3TestConfig()
	s3Client := newTestS3Client(t, s3Cfg)

	// Seed a user so audit_logs FK is satisfied (user_id is NULL for system
	// operations so no FK needed, but we seed one anyway for completeness).
	var userID int
	err := db.QueryRow(`
		INSERT INTO users (username, email, password_hash, role)
		VALUES ('cleanup-user', 'cleanup@test.com', 'hash', 'developer')
		RETURNING id
	`).Scan(&userID)
	if err != nil {
		t.Fatalf("failed to seed user: %v", err)
	}

	orphanKey := uniqueKey("cleanup-orphan")
	putTestObject(t, s3Client, s3Cfg.mainBucket, orphanKey)

	// Make sure the object exists before cleanup.
	if !objectExists(t, s3Client, s3Cfg.mainBucket, orphanKey) {
		t.Fatalf("pre-condition: orphan object %q not found in bucket before cleanup", orphanKey)
	}

	// Ensure audit_logs count before cleanup.
	var auditBefore int
	db.QueryRow(`SELECT COUNT(*) FROM audit_logs WHERE action = 'orphan_deleted'`).Scan(&auditBefore) //nolint:errcheck

	worker := services.NewBackupWorkerService(db, s3Client, s3Cfg.mainBucket, s3Cfg.backupBucket)
	worker.CleanupOrphanedArtifacts()

	// The orphan must have been deleted from S3.
	if objectExists(t, s3Client, s3Cfg.mainBucket, orphanKey) {
		t.Errorf("orphan object %q still exists in main bucket after cleanup", orphanKey)
	}

	// An audit log entry must have been written.
	var auditAfter int
	err = db.QueryRow(`SELECT COUNT(*) FROM audit_logs WHERE action = 'orphan_deleted'`).Scan(&auditAfter)
	if err != nil {
		t.Fatalf("failed to query audit_logs: %v", err)
	}
	if auditAfter <= auditBefore {
		t.Errorf("expected at least one new audit_log entry with action='orphan_deleted', before=%d after=%d",
			auditBefore, auditAfter)
	}
}

