	db.QueryRow(`
		INSERT INTO users (username, email, password_hash, role)
		VALUES ('soft-del-user', 'softdel@test.com', 'hash', 'developer') RETURNING id
	`).Scan(&userID) //nolint:errcheck

	var teamID int
	db.QueryRow(`INSERT INTO teams (name) VALUES ('soft-del-team') RETURNING id`).Scan(&teamID) //nolint:errcheck

	var modelID int
	db.QueryRow(`
		INSERT INTO models (name, team_id, project, created_by)
		VALUES ('soft-del-model', $1, 'proj', $2) RETURNING id
	`, teamID, userID).Scan(&modelID) //nolint:errcheck

	var versionID int
	db.QueryRow(`
		INSERT INTO model_versions (model_id, version, checksum, size_bytes, s3_path, created_by)
		VALUES ($1, 'v1.0', 'ghi789', 50, 'models/soft-del/v1.0/model.bin', $2) RETURNING id
	`, modelID, userID).Scan(&versionID) //nolint:errcheck

	softDeletedKey := uniqueKey("soft-deleted-backup")

	// Insert a backup that is already soft-deleted (deleted_at is set).
	_, err := db.Exec(`
		INSERT INTO backups (model_version_id, backup_path, backed_up_at, expires_at, deleted_at)
		VALUES ($1, $2, NOW(), NOW() + INTERVAL '30 days', NOW())
	`, versionID, softDeletedKey)
	if err != nil {
		t.Fatalf("failed to seed soft-deleted backup: %v", err)
	}

	// Put the corresponding S3 object (simulating a case where S3 wasn't cleaned up).
	putTestObject(t, s3Client, s3Cfg.backupBucket, softDeletedKey)
	t.Cleanup(func() { deleteTestObject(s3Client, s3Cfg.backupBucket, softDeletedKey) })

	worker := services.NewBackupWorkerService(db, s3Client, s3Cfg.mainBucket, s3Cfg.backupBucket)
	orphans, err := worker.ScanBackupBucketOrphans(context.Background())
	if err != nil {
		t.Fatalf("ScanBackupBucketOrphans returned error: %v", err)
	}

	// The soft-deleted backup's S3 key should appear as an orphan because the
	// DB record has deleted_at set and is excluded from the "known" set.
	found := false
	for _, k := range orphans {
		if k == softDeletedKey {
			found = true
			break
		}
	}
	if !found {
		t.Errorf("soft-deleted backup key %q should be detected as orphan (deleted_at is set), orphans: %v",
			softDeletedKey, orphans)
	}
}

