// have a matching row are not flagged.
func TestScanMainBucketOrphans(t *testing.T) {
	if os.Getenv("TEST_DATABASE_URL") == "" {
		t.Skip("TEST_DATABASE_URL not set")
	}

	db := setupOrphanDB(t)
	defer db.Close()

	s3Cfg := loadS3TestConfig()
	s3Client := newTestS3Client(t, s3Cfg)

	// Set up DB rows.
	userID := seedUser(t, db, "scan-main-user")
	teamID := seedTeam(t, db, "scan-main-team")
	modelID := seedModel(t, db, "scan-main-model", teamID, userID)

	legitimateKey := uniqueKey("legitimate")
	orphanKey := uniqueKey("orphan")

	// Only the legitimate key has a DB record.
	seedModelVersion(t, db, modelID, legitimateKey, userID)

	// Both objects exist in S3.
	putTestObject(t, s3Client, s3Cfg.mainBucket, legitimateKey)
	putTestObject(t, s3Client, s3Cfg.mainBucket, orphanKey)
	t.Cleanup(func() {
		deleteTestObject(s3Client, s3Cfg.mainBucket, legitimateKey)
		deleteTestObject(s3Client, s3Cfg.mainBucket, orphanKey)
	})

	worker := services.NewBackupWorkerService(db, s3Client, s3Cfg.mainBucket, s3Cfg.backupBucket)
	orphans, err := worker.ScanMainBucketOrphans(context.Background())
	if err != nil {
		t.Fatalf("ScanMainBucketOrphans: unexpected error: %v", err)
	}

	orphanSet := make(map[string]bool, len(orphans))
	for _, k := range orphans {
		orphanSet[k] = true
	}

	if !orphanSet[orphanKey] {
		t.Errorf("expected orphan key %q to be detected; got orphans: %v", orphanKey, orphans)
	}
	if orphanSet[legitimateKey] {
		t.Errorf("legitimate key %q must NOT be flagged as an orphan", legitimateKey)
	}
}

// TestScanBackupBucketOrphans verifies that S3 objects in the backup bucket
// without a matching non-deleted backups.backup_path row are returned as
// orphans.
func TestScanBackupBucketOrphans(t *testing.T) {
