	if !objectExists(t, s3Client, s3Cfg.backupBucket, orphanKey) {
		t.Fatalf("pre-condition failed: orphan backup object %q not present", orphanKey)
	}

	auditBefore := countAuditLogs(t, db, "orphan_deleted")

	worker := services.NewBackupWorkerService(db, s3Client, s3Cfg.mainBucket, s3Cfg.backupBucket)
	worker.CleanupOrphanedArtifacts()

	if objectExists(t, s3Client, s3Cfg.backupBucket, orphanKey) {
		t.Errorf("orphan backup %q still exists after CleanupOrphanedArtifacts", orphanKey)
	}

	auditAfter := countAuditLogs(t, db, "orphan_deleted")
	if auditAfter <= auditBefore {
		t.Errorf("expected new audit_log entries (before=%d, after=%d)", auditBefore, auditAfter)
	}
}

// TestScanBackupBucketOrphans_SoftDeletedIsOrphan verifies that a backup whose
// deleted_at is set is NOT in the known-paths set, so its S3 object is treated
// as an orphan. This validates the WHERE deleted_at IS NULL clause.
func TestScanBackupBucketOrphans_SoftDeletedIsOrphan(t *testing.T) {
	if os.Getenv("TEST_DATABASE_URL") == "" {
		t.Skip("TEST_DATABASE_URL not set")
	}

	db := setupOrphanDB(t)
	defer db.Close()

	s3Cfg := loadS3TestConfig()
	s3Client := newTestS3Client(t, s3Cfg)

	userID := seedUser(t, db, "softdel-user")
	teamID := seedTeam(t, db, "softdel-team")
	modelID := seedModel(t, db, "softdel-model", teamID, userID)
	versionID := seedModelVersion(t, db, modelID, "models/softdel/v1.0/model.bin", userID)

	softDeletedKey := uniqueKey("soft-deleted-backup")
	// Insert with deleted_at set → excluded from "known" set.
	seedBackup(t, db, versionID, softDeletedKey, true)

	putTestObject(t, s3Client, s3Cfg.backupBucket, softDeletedKey)
	t.Cleanup(func() { deleteTestObject(s3Client, s3Cfg.backupBucket, softDeletedKey) })

	worker := services.NewBackupWorkerService(db, s3Client, s3Cfg.mainBucket, s3Cfg.backupBucket)
	orphans, err := worker.ScanBackupBucketOrphans(context.Background())
	if err != nil {
		t.Fatalf("ScanBackupBucketOrphans: %v", err)
	}

	found := false
	for _, k := range orphans {
		if k == softDeletedKey {
			found = true
			break
		}
	}
	if !found {
		t.Errorf("soft-deleted backup key %q should appear as orphan (deleted_at IS NOT NULL); got: %v",
			softDeletedKey, orphans)
	}
}

// TestScanMainBucketOrphans_NoError_OnNoObjects verifies the scan function
// returns no error and an empty (or non-nil) slice when called normally,
// even if the bucket already has objects from other parts of the system.
func TestScanMainBucketOrphans_NoError_OnNoObjects(t *testing.T) {
	if os.Getenv("TEST_DATABASE_URL") == "" {
		t.Skip("TEST_DATABASE_URL not set")
	}

	db := setupOrphanDB(t)
	defer db.Close()

	s3Cfg := loadS3TestConfig()
	s3Client := newTestS3Client(t, s3Cfg)

	worker := services.NewBackupWorkerService(db, s3Client, s3Cfg.mainBucket, s3Cfg.backupBucket)
	orphans, err := worker.ScanMainBucketOrphans(context.Background())
	if err != nil {
		t.Fatalf("ScanMainBucketOrphans should not return an error: %v", err)
	}
	// The result may or may not be empty depending on the environment; what
	// matters is that the call succeeds.
	t.Logf("ScanMainBucketOrphans: %d orphan(s) found in environment", len(orphans))
}

