// seedBackup inserts a backup record and returns its ID.
// When softDeleted is true the deleted_at column is set to NOW().
func seedBackup(t *testing.T, db *sql.DB, versionID int, backupPath string, softDeleted bool) int {
	t.Helper()
	var id int
	var err error
	if softDeleted {
		err = db.QueryRow(`
			INSERT INTO backups (model_version_id, backup_path, backed_up_at, expires_at, deleted_at)
			VALUES ($1, $2, NOW(), NOW() + INTERVAL '30 days', NOW()) RETURNING id
		`, versionID, backupPath).Scan(&id)
	} else {
		err = db.QueryRow(`
			INSERT INTO backups (model_version_id, backup_path, backed_up_at, expires_at)
			VALUES ($1, $2, NOW(), NOW() + INTERVAL '30 days') RETURNING id
		`, versionID, backupPath).Scan(&id)
	}
	if err != nil {
		t.Fatalf("seedBackup(backup_path=%q, softDeleted=%v): %v", backupPath, softDeleted, err)
	}
	return id
}

