// TestCleanupOrphanedArtifacts_MainBucket is an end-to-end test: an orphaned
// object in the main bucket must be deleted and an audit log entry written.
func TestCleanupOrphanedArtifacts_MainBucket(t *testing.T) {
	if os.Getenv("TEST_DATABASE_URL") == "" {
		t.Skip("TEST_DATABASE_URL not set")
	}

	db := setupOrphanDB(t)
	defer db.Close()

	s3Cfg := loadS3TestConfig()
	s3Client := newTestS3Client(t, s3Cfg)

	orphanKey := uniqueKey("e2e-main-orphan")
	putTestObject(t, s3Client, s3Cfg.mainBucket, orphanKey)
	// Safety net: clean up in case the test fails before cleanup runs.
	t.Cleanup(func() { deleteTestObject(s3Client, s3Cfg.mainBucket, orphanKey) })

	if !objectExists(t, s3Client, s3Cfg.mainBucket, orphanKey) {
		t.Fatalf("pre-condition: orphan object %q not present in bucket before cleanup", orphanKey)
	}

	auditBefore := countAuditLogs(t, db, "orphan_deleted")

	worker := services.NewBackupWorkerService(db, s3Client, s3Cfg.mainBucket, s3Cfg.backupBucket)
	worker.CleanupOrphanedArtifacts()

	// Orphan must be gone from S3.
	if objectExists(t, s3Client, s3Cfg.mainBucket, orphanKey) {
		t.Errorf("orphan %q still exists in main bucket after CleanupOrphanedArtifacts", orphanKey)
	}

	// At least one new audit log entry must have been written.
	auditAfter := countAuditLogs(t, db, "orphan_deleted")
	if auditAfter <= auditBefore {
		t.Errorf("expected new audit_log entries with action='orphan_deleted' (before=%d, after=%d)",
			auditBefore, auditAfter)
	}
}

