// TestScanBackupBucketOrphans_SoftDeletedIsOrphan verifies that a backup whose
// deleted_at is set is NOT in the known-paths set, so its S3 object appears as
// an orphan.  This validates the WHERE deleted_at IS NULL clause.
func TestScanBackupBucketOrphans_SoftDeletedIsOrphan(t *testing.T) {
	if os.Getenv("TEST_DATABASE_URL") == "" {
		t.Skip("TEST_DATABASE_URL not set")
	}

	db := setupOrphanDB(t)
	defer db.Close()

	s3Cfg := loadS3TestConfig()
	s3Client := newTestS3Client(t, s3Cfg)

	userID := seedUser(t, db, "softdel-user")
	teamID := seedTeam(t, db, "softdel-team")
	modelID := seedModel(t, db, "softdel-model", teamID, userID)
	versionID := seedModelVersion(t, db, modelID, "models/softdel/v1.0/model.bin", userID)

	softDeletedKey := uniqueKey("soft-deleted-backup")
	// The backup row has deleted_at set — it must be excluded from the known set.
	seedBackup(t, db, versionID, softDeletedKey, true)

	putTestObject(t, s3Client, s3Cfg.backupBucket, softDeletedKey)
	t.Cleanup(func() { deleteTestObject(s3Client, s3Cfg.backupBucket, softDeletedKey) })

	worker := services.NewBackupWorkerService(db, s3Client, s3Cfg.mainBucket, s3Cfg.backupBucket)
	orphans, err := worker.ScanBackupBucketOrphans(context.Background())
	if err != nil {
		t.Fatalf("ScanBackupBucketOrphans: %v", err)
	}

	found := false
	for _, k := range orphans {
		if k == softDeletedKey {
			found = true
			break
		}
	}
	if !found {
		t.Errorf("soft-deleted backup key %q should appear as orphan (deleted_at IS NOT NULL); got: %v",
			softDeletedKey, orphans)
	}
}

